20	/// Command execution context.
21	pub const Context = struct {
22	    server: *Server,
23	    session: ?*Session,
24	    window: ?*Window,
25	    pane: ?*Pane,
26	    client_index: ?usize = null,
27	    allocator: std.mem.Allocator,
28	    reply_fd: ?std.c.fd_t = null,
29	    registry: ?*const Registry = null,
30	    binding_manager: ?*binding_mod.BindingManager = null,
31	};
32	
33	/// Command handler function type.
34	pub const Handler = *const fn (ctx: *Context, args: []const []const u8) CmdError!void;
35	
36	pub const CmdError = error{
37	    InvalidArgs,
38	    SessionNotFound,
39	    WindowNotFound,
40	    PaneNotFound,
41	    BufferNotFound,
42	    CommandFailed,
43	    OutOfMemory,
44	};
45	
46	/// A registered command.
47	pub const CommandDef = struct {
48	    name: []const u8,
49	    alias: ?[]const u8,
50	    min_args: u8,
51	    max_args: u8,
52	    usage: []const u8,
53	    handler: Handler,
54	};
55	
56	/// Command registry.
57	pub const Registry = struct {
58	    commands: std.StringHashMap(CommandDef),
59	
60	    pub fn init(alloc: std.mem.Allocator) Registry {
61	        return .{ .commands = std.StringHashMap(CommandDef).init(alloc) };
62	    }
63	
64	    pub fn deinit(self: *Registry) void {
65	        self.commands.deinit();
66	    }
67	
68	    pub fn register(self: *Registry, def: CommandDef) !void {
69	        try self.commands.put(def.name, def);
70	        if (def.alias) |alias| {
71	            try self.commands.put(alias, def);
72	        }
73	    }
74	
75	    pub fn find(self: *const Registry, name: []const u8) ?CommandDef {
76	        return self.commands.get(name);
77	    }
78	
79	    /// Return a sorted, deduplicated list of all commands (aliases excluded).
80	    pub fn listAll(self: *const Registry, alloc: std.mem.Allocator) ![]CommandDef {
81	        var seen = std.StringHashMap(void).init(alloc);
82	        defer seen.deinit();
83	        var list: std.ArrayListAligned(CommandDef, null) = .empty;
84	        defer list.deinit(alloc);
85	
86	        var iter = self.commands.iterator();
87	        while (iter.next()) |entry| {
88	            const def = entry.value_ptr.*;
89	            if (seen.contains(def.name)) continue;
90	            try seen.put(def.name, {});
91	            try list.append(alloc, def);
92	        }
93	
94	        const items = try alloc.dupe(CommandDef, list.items);
95	        std.mem.sort(CommandDef, items, {}, struct {
96	            fn lessThan(_: void, a: CommandDef, b: CommandDef) bool {
97	                return std.mem.order(u8, a.name, b.name) == .lt;
98	            }
99	        }.lessThan);
100	        return items;
101	    }
102	
103	    /// Execute a command by name with arguments.
104	    pub fn execute(self: *const Registry, ctx: *Context, name: []const u8, args: []const []const u8) CmdError!void {
105	        const def = self.find(name) orelse return CmdError.CommandFailed;
106	        if (args.len < def.min_args or (def.max_args > 0 and args.len > def.max_args)) {
107	            return CmdError.InvalidArgs;
108	        }
109	        return def.handler(ctx, args);
110	    }
111	
112	    pub fn executeParsed(self: *const Registry, ctx: *Context, command: *const config_parser.Command) CmdError!void {
113	        return self.execute(ctx, command.name, command.args.items);
114	    }
