240	fn writeReplyMessage(ctx: *Context, msg_type: protocol.MessageType, message: []const u8) CmdError!void {
241	    if (ctx.reply_fd) |fd| {
242	        protocol.sendMessage(fd, msg_type, message) catch return CmdError.CommandFailed;
243	        return;
244	    }
245	
246	    const target_fd: std.c.fd_t = switch (msg_type) {
247	        .error_msg => 2,
248	        else => 1,
249	    };
250	    _ = std.c.write(target_fd, message.ptr, message.len);
251	}
