259	fn spawnWindowPane(alloc: std.mem.Allocator, shell: [:0]const u8, sx: u32, sy: u32) CmdError!*Pane {
260	    const pane = Pane.init(alloc, sx, sy) catch return CmdError.OutOfMemory;
261	    errdefer pane.deinit();
262	
263	    var pty = Pty.openPty() catch return CmdError.CommandFailed;
264	    pty.forkExec(shell, null) catch return CmdError.CommandFailed;
265	    pty.resize(@intCast(sx), @intCast(sy));
266	    pane.fd = pty.master_fd;
267	    pane.pid = pty.pid;
268	    return pane;
269	}
