271	fn parseTargetWindow(args: []const []const u8) ?u32 {
272	    var i: usize = 0;
273	    while (i < args.len) : (i += 1) {
274	        if (!std.mem.eql(u8, args[i], "-t") or i + 1 >= args.len) continue;
275	        i += 1;
276	        const target = args[i];
277	        if (target.len >= 2 and target[0] == ':') {
278	            return std.fmt.parseInt(u32, target[1..], 10) catch null;
279	        }
280	        return std.fmt.parseInt(u32, target, 10) catch null;
281	    }
282	    return null;
283	}
