            .id = next_id,
            .pid = 0,
            .fd = -1,
            .sx = sx,
            .sy = sy,
            .xoff = 0,
            .yoff = 0,
            .flags = .{},
            .copy_state = null,
            .prompt_state = null,
            .choose_tree_state = null,
            .allocator = alloc,
        };
        next_id += 1;
        return p;
    }

    pub fn deinit(self: *Pane) void {
        if (self.fd >= 0) {
